#!/usr/bin/env python3n"""book-canvas-server.py"""nimport asyncio,json,os,uuid,threading,loggingnfrom http.server import HTTPServer,SimpleHTTPRequestHandlernfrom pathlib import Pathnfrom datetime import datetimenfrom collections import defaultdictnnHTTP_PORT,WS_PORT=3001,3002nBASE_DIR=Path(__file__).parentnSTATIC_DIR=BASE_DIR/'ui/public'nLOG_DIR=BASE_DIR/'logs'nLOG_DIR.mkdir(exist_ok=True)nlogging.basicConfig(level=logging.INFO,format='%(asctime)s %(message)s',handlers=[logging.FileHandler(LOG_DIR/'server.log'),logging.StreamHandler()])nlogger=logging.getLogger('book-canvas')nnclass Storage:n    def __init__(self):self._s,self._c={},defaultdict(set)n    def cs(self,uid='a'):sid=f"s_{uuid.uuid().hex}";self._s[sid]={'id':sid,'u':uid,'c':datetime.now().isoformat(),'cv':{'vp':{'x':0,'y':0,'z':1},'n':[],'con':[]},'d':[]};return self._s[sid]n    def gs(self,s):return self._s.get(s)n    def us(self,s,d):return self._s[s].update(d) if s in self._s else Falsennstorage=Storage()nnclass H(SimpleHTTPRequestHandler):n    def __init__(self,*a,**k):super().__init__(*a,directory=str(STATIC_DIR),**k)n    def _j(self,s=200,d=None):self.send_response(s);self.send_header('Content-Type','application/json');self.send_header('Access-Control-Allow-Origin','*');self.end_headers();self.wfile.write(json.dumps(d or {}).encode())n    def do_GET():n        if p=='/api/status':self._j(200,{'status':'running','sessions':len(storage._s)})n        elif p=='/api/sessions':self._j(200,[{'id':s['id'],'userId':s['u']}for s in storage._s.values()])n        else:return super().do_GET()n    def do_POST():n        if p=='/api/session/create':s=storage.cs();self._j(201,{'sessionId':s['id']})n        else:self._j(404)n    def log_message(self,f,*a):logger.info(f"{self.client_address[0]} - {f%a}")nnclass WSH:n    def __init__(self):self.c={}n    async def h(self,ws,p):cid=str(uuid.uuid4());logger.info(f'WS:{cid}');await ws.send(json.dumps({'type':'joined','cid':cid}))n    async def b(self,sid,d,e=[]):n        for cid in storage._c.get(sid,[]):n            if cid in self.c and cid not in e:await self.c[cid].send(json.dumps(d))nnws=WSH()ndef main():n    logger.info(f'HTTP:http://localhost:{HTTP_PORT}')n    HTTPServer(('localhost',HTTP_PORT),H).serve_forever()nnif __name__=='__main__': main()